+import React from 'react';
+
+const brickWidth = 60;
+const brickHeight = 30;
+const mortarSize = 4;
+const rows = 6;
+const cols = 10;
+
+// Utility to generate color variation per brick
+function brickColor(row, col) {
+  const baseR = 150;
+  const baseG = 100;
+  const baseB = 80;
+  // Slight random variation based on position for consistency
+  const variation = ((row * 7 + col * 13) % 20) - 10;
+  return `rgb(${baseR + variation},${baseG + variation / 2},${baseB + variation / 3})`;
+}
+
+// Create shadow gradient for 3D effect
+function Brick({ x, y, color }) {
+  return (
+    <g transform={`translate(${x},${y})`}>
+      {/* Brick base */}
+      <rect
+        width={brickWidth}
+        height={brickHeight}
+        fill={color}
+        stroke="#6b4c3b"
+        strokeWidth="1"
+        rx="4"
+        ry="4"
+      />
+      {/* Highlight top edge */}
+      <path
+        d={`M0 0 L${brickWidth} 0 L${brickWidth - 6} 6 L6 6 Z`}
+        fill="rgba(255,255,255,0.3)"
+      />
+      {/* Shadow bottom edge */}
+      <path
+        d={`M0 ${brickHeight} L${brickWidth} ${brickHeight} L${brickWidth - 6} ${brickHeight - 6} L6 ${brickHeight - 6} Z`}
+        fill="rgba(0,0,0,0.25)"
+      />
+    </g>
+  );
+}
+
+export default function StoneWall() {
+  const bricks = [];
+  for (let row = 0; row < rows; row++) {
+    for (let col = 0; col < cols; col++) {
+      // Offset every other row for staggered bricks
+      const offsetX = (row % 2) * (brickWidth / 2);
+      const x = col * (brickWidth + mortarSize) - offsetX;
+      const y = row * (brickHeight + mortarSize);
+      const color = brickColor(row, col);
+      bricks.push(<Brick key={`${row}-${col}`} x={x} y={y} color={color} />);
+    }
+  }
+
+  // Mortar lines as a light gray background
+  return (
+    <svg
+      width={(brickWidth + mortarSize) * cols + brickWidth / 2}
+      height={(brickHeight + mortarSize) * rows}
+      style={{ backgroundColor: '#dcdcdc' }}
+    >
+      {bricks}
+    </svg>
+  );
+}
